method ArraySum(a: array<int>) returns (s: int)
  requires a != null
  requires forall i :: 0 <= i < a.Length ==> a[i] >= 0
  ensures s >= 0
  ensures forall i :: 0 <= i < a.Length ==> s >= a[i]
{
  s := 0;
  for i := 0 to a.Length
    invariant s >= 0
    invariant forall j :: 0 <= j < i ==> s >= a[j]
  {
    s := s + a[i];
  }
}

method BinarySearch(a: array<int>, key: int) returns (found: bool, index: int)
  requires a != null
  requires forall i, j :: 0 <= i < j < a.Length ==> a[i] <= a[j]
  ensures found ==> 0 <= index < a.Length && a[index] == key
  ensures !found ==> forall i :: 0 <= i < a.Length ==> a[i] != key
{
  var lo, hi := 0, a.Length;
  while lo < hi
    invariant 0 <= lo <= hi <= a.Length
    invariant forall i :: 0 <= i < lo ==> a[i] < key
    invariant forall i :: hi <= i < a.Length ==> a[i] > key
  {
    var mid := lo + (hi - lo) / 2;
    if a[mid] == key { found, index := true, mid; return; }
    else if a[mid] < key { lo := mid + 1; }
    else { hi := mid; }
  }
  found, index := false, -1;
}

method LinearSearch(a: array<int>, key: int) returns (found: bool, index: int)
  requires a != null
  ensures found ==> 0 <= index < a.Length && a[index] == key
  ensures !found ==> forall i :: 0 <= i < a.Length ==> a[i] != key
{
  index := 0;
  while index < a.Length
    invariant 0 <= index <= a.Length
    invariant forall i :: 0 <= i < index ==> a[i] != key
  {
    if a[index] == key { found := true; return; }
    index := index + 1;
  }
  found := false;
  index := -1;
}

method BubbleSort(a: array<int>)
  requires a != null
  modifies a
  ensures forall i, j :: 0 <= i < j < a.Length ==> a[i] <= a[j]
{
  for i := 0 to a.Length
    invariant forall k, l :: 0 <= k < l < i ==> a[k] <= a[l]
  {
    for j := 0 to a.Length - i - 1
      invariant forall k :: 0 <= k < j ==> a[k] <= a[j]
    {
      if a[j] > a[j+1] {
        var t := a[j];
        a[j] := a[j+1];
        a[j+1] := t;
      }
    }
  }
}

