method IsPrime(n: int) returns (p: bool)
  requires n > 1
  ensures p ==> forall k :: 2 <= k < n ==> n % k != 0
  ensures !p ==> exists k :: 2 <= k < n && n % k == 0
{
  p := true;
  for k := 2 to n
    invariant p ==> forall j :: 2 <= j < k ==> n % j != 0
  {
    if n % k == 0 && k < n { p := false; }
  }
}

method Transpose(a: array2<int>) returns (b: array2<int>)
  requires a != null
  ensures b != null
  ensures b.Length0 == a.Length1
  ensures b.Length1 == a.Length0
  ensures forall i, j :: 0 <= i < a.Length1 && 0 <= j < a.Length0 ==> b[i,j] == a[j,i]
{
  b := new int[a.Length1, a.Length0];
  for i := 0 to a.Length1
    forall j | 0 <= j < a.Length0
      ensures b[i,j] == a[j,i]
    {
      b[i,j] := a[j,i];
    }
}

method Merge(a: array<int>, b: array<int>) returns (c: array<int>)
  requires a != null && b != null
  requires forall i, j :: 0 <= i < j < a.Length ==> a[i] <= a[j]
  requires forall i, j :: 0 <= i < j < b.Length ==> b[i] <= b[j]
  ensures c != null
  ensures c.Length == a.Length + b.Length
  ensures forall i, j :: 0 <= i < j < c.Length ==> c[i] <= c[j]
{
  c := new int[a.Length + b.Length];
  var i, j, k := 0, 0, 0;
  while i < a.Length || j < b.Length
    invariant 0 <= k <= c.Length
    invariant forall m, n :: 0 <= m < n < k ==> c[m] <= c[n]
  {
    if i < a.Length && (j >= b.Length || a[i] <= b[j]) {
      c[k] := a[i]; i := i + 1;
    } else {
      c[k] := b[j]; j := j + 1;
    }
    k := k + 1;
  }
}

method EuclideanAlgorithm(a: nat, b: nat) returns (g: nat)
