}

class Stack<T> {
  var data: seq<T>;

  constructor()
    ensures data == []
  {
    data := [];
  }

  method Push(x: T)
    ensures |data| == old(|data|) + 1
    ensures data[0] == x
    ensures forall i :: 1 <= i < |data| ==> data[i] == old(data)[i-1]
  {
    data := [x] + data;
  }
}

class Queue<T> {
  var items: seq<T>;

  constructor()
    ensures items == []
  {
    items := [];
  }

  method Enqueue(x: T)
    ensures |items| == old(|items|) + 1
    ensures items[|items|-1] == x
    ensures forall i :: 0 <= i < old(|items|) ==> items[i] == old(items)[i]
  {
    items := items + [x];
  }
}

